33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioOutput {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
57	  sword: 100,
58	  amulet: 60,
59	  staff: 80,
60	  potion: 40,
61	};
62	
63	const basePremium = (item: Item): number =>
64	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
65	
66	const quotePremium = (items: Item[]): number =>
67	  items.reduce((sum, item) => sum + basePremium(item), 0) + PROCESSING_FEE;
68	
69	export const processScenario = (scenario: Scenario): ScenarioOutput => {
70	  const step = scenario.steps[0] as QuoteStep;
71	  return { results: [{ premium: quotePremium(step.items) }] };
72	};
